-- MySQL 8 Database Schema Script\n\n-- Users Table\nCREATE TABLE users (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    username VARCHAR(255) NOT NULL UNIQUE,\n    password VARCHAR(255) NOT NULL,\n    email VARCHAR(255) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Workspaces Table\nCREATE TABLE workspaces (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    owner_id INT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (owner_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Workspace Members Table\nCREATE TABLE workspace_members (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    workspace_id INT,\n    user_id INT,\n    role VARCHAR(50),\n    FOREIGN KEY (workspace_id) REFERENCES workspaces(id) ON DELETE CASCADE,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Boards Table\nCREATE TABLE boards (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    workspace_id INT,\n    name VARCHAR(255) NOT NULL,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (workspace_id) REFERENCES workspaces(id) ON DELETE CASCADE\n);\n\n-- Board Members Table\nCREATE TABLE board_members (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    board_id INT,\n    user_id INT,\n    FOREIGN KEY (board_id) REFERENCES boards(id) ON DELETE CASCADE,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Tasks Table\nCREATE TABLE tasks (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    board_id INT,\n    name VARCHAR(255) NOT NULL,\n    status VARCHAR(50),\n    priority VARCHAR(50),\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (board_id) REFERENCES boards(id) ON DELETE CASCADE\n);\n\n-- Task Assignees Table\nCREATE TABLE task_assignees (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    task_id INT,\n    user_id INT,\n    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Tags Table\nCREATE TABLE tags (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    name VARCHAR(255) NOT NULL UNIQUE\n);\n\n-- Task Tags Table\nCREATE TABLE task_tags (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    task_id INT,\n    tag_id INT,\n    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,\n    FOREIGN KEY (tag_id) REFERENCES tags(id) ON DELETE CASCADE\n);\n\n-- Task Comments Table\nCREATE TABLE task_comments (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    task_id INT,\n    comment TEXT,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE\n);\n\n-- Board Columns Table\nCREATE TABLE board_columns (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    board_id INT,\n    name VARCHAR(255) NOT NULL,\n    position INT,\n    FOREIGN KEY (board_id) REFERENCES boards(id) ON DELETE CASCADE\n);\n\n-- Task Column Values Table\nCREATE TABLE task_column_values (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    task_id INT,\n    column_id INT,\n    value TEXT,\n    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,\n    FOREIGN KEY (column_id) REFERENCES board_columns(id) ON DELETE CASCADE\n);\n\n-- Task Dependencies Table\nCREATE TABLE task_dependencies (\n    id INT AUTO_INCREMENT PRIMARY KEY,\n    task_id INT,\n    depends_on_task_id INT,\n    FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE,\n    FOREIGN KEY (depends_on_task_id) REFERENCES tasks(id) ON DELETE CASCADE\n);\n\n-- Seed Data for Default Statuses\nINSERT INTO tasks (name, status, priority) VALUES (\n    ('Task 1', 'Open', 'High'),\n    ('Task 2', 'In Progress', 'Medium'),\n    ('Task 3', 'Done', 'Low')\n);\n\n-- Seed Data for Default Priorities\nINSERT INTO tags (name) VALUES (\n    ('High'),\n    ('Medium'),\n    ('Low')\n);\n\n-- Seed Data for Default Roles\nINSERT INTO workspace_members (workspace_id, user_id, role) VALUES (\n    (1, 1, 'Admin'),\n    (1, 2, 'Member')\n);\n